import React from 'react'
import {GrFormClose} from 'react-icons/gr'

const Popup = (props) => {
  return (props.trigger)?(
    <div className='bg-richblack-900 blur-sm h-[100vh] w-full'>
        <div className='bg-richblack-900 blur-none'>
            <button className='bg-[#F70000] p-2 hover:bg-[#ec0404]'>
                <GrFormClose fontSize={20} fill='#AFB2BF' className='hover: ease-in duration-300 cursor-pointer'/>
            </button>
                {props.children}
        </div>
    </div>
  ):"";
}

export default Popup
